为了确保导入功能（自动解析 CSV/Excel）更加智能和稳健，特别是针对“手机号”这一新字段的自动识别，我优化了 `processCSV` 函数。现在它会动态寻找表头（如“姓名”、“手机”、“编号”、“4.26”等），而不是依赖固定的列顺序。

以下是更新后的代码：

# Updated files:

## components/StaffRegistration.tsx

-   **智能导入解析**：重写了 `processCSV`，通过表头名称动态定位数据列（编号、姓名、手机、日期等），不再依赖固定索引。
-   **分隔符兼容**：增强了对 CSV（逗号分隔）和 Excel 复制数据（Tab 分隔）的兼容性。
-   **日期自动同步**：导入时会自动扫描表头中的日期（如 `5.1`），并将其添加到系统的日期列中，防止数据丢失。
-   **提示优化**：导入成功后会提示识别到的记录数和日期列。

<![CDATA[
import React, { useState, useMemo, useRef } from 'react';
import { RegistrationRecord, Group, Staff } from '../types';
import { 
  Search, 
  UploadCloud, 
  Trash2, 
  X, 
  FileText, 
  Calendar, 
  MapPin, 
  User, 
  Sun, 
  Moon, 
  Check, 
  FileSpreadsheet,
  Edit,
  Circle,
  Ban,
  Settings,
  Download,
  Plus,
  CalendarDays,
  Layout,
  Phone
} from 'lucide-react';

interface StaffRegistrationProps {
  records: RegistrationRecord[];
  onUpdateRecords: (records: RegistrationRecord[]) => void;
  groups: Group[];
  onBatchAddStaff: (staffList: Staff[]) => void;
  existingStaffList: Staff[];
}

// Availability States Configuration
const AVAILABILITY_STATES = ['EMPTY', 'FULL', 'AM', 'PM', 'ABSENT'] as const;
type AvailabilityState = typeof AVAILABILITY_STATES[number];

const STATE_CONFIG: Record<AvailabilityState, { label: string; shortLabel: string; bg: string; text: string; border: string; icon: React.ReactNode }> = {
  EMPTY: { 
    label: '未填', 
    shortLabel: '缺', 
    bg: 'bg-white', 
    text: 'text-gray-300', 
    border: 'border-gray-100',
    icon: <Circle size={8} className="opacity-20" /> 
  },
  FULL: { 
    label: '全天', 
    shortLabel: '全', 
    bg: 'bg-emerald-100', 
    text: 'text-emerald-700', 
    border: 'border-emerald-200',
    icon: <Check size={10} strokeWidth={3} /> 
  },
  AM: { 
    label: '上午', 
    shortLabel: '上', 
    bg: 'bg-blue-100', 
    text: 'text-blue-700', 
    border: 'border-blue-200',
    icon: <Sun size={10} /> 
  },
  PM: { 
    label: '下午', 
    shortLabel: '下', 
    bg: 'bg-orange-100', 
    text: 'text-orange-700', 
    border: 'border-orange-200',
    icon: <Moon size={10} /> 
  },
  ABSENT: {
    label: '缺勤',
    shortLabel: '缺', 
    bg: 'bg-gray-50', 
    text: 'text-gray-400', 
    border: 'border-gray-200',
    icon: <Ban size={10} />
  }
};

const StaffRegistration: React.FC<StaffRegistrationProps> = ({ 
  records, 
  onUpdateRecords, 
  groups, 
  onBatchAddStaff, 
  existingStaffList 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<RegistrationRecord | null>(null);

  // Date Management State
  const [availableDates, setAvailableDates] = useState<string[]>(["4.26", "5.1", "5.2", "5.3", "5.4", "5.5"]);
  const [isDateManagerOpen, setIsDateManagerOpen] = useState(false);
  const [newDateInput, setNewDateInput] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Derived filtered records
  const filteredRecords = useMemo(() => {
    return records.filter(record => 
      record.name.includes(searchTerm) || 
      record.registrationNumber.includes(searchTerm) ||
      (record.notes && record.notes.includes(searchTerm)) ||
      (record.phone && record.phone.includes(searchTerm))
    );
  }, [records, searchTerm]);

  // Handle file upload
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const content = evt.target?.result as string;
      processCSV(content);
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // Process CSV/Excel Data (Enhanced)
  const processCSV = (content: string) => {
    // 1. Split lines
    const lines = content.split(/\r?\n/).filter(line => line.trim() !== '');
    if (lines.length < 2) {
      alert("文件内容过少，请确保包含表头和数据行");
      return;
    }

    // 2. Identify Separator (Comma for CSV, Tab for Excel Copy-Paste)
    const separator = lines[0].includes('\t') ? '\t' : ',';

    // 3. Parse Header
    const headers = lines[0].split(separator).map(h => h.trim().replace(/^"|"$/g, ''));

    // 4. Dynamic Column Mapping
    const idxMap = {
      num: headers.findIndex(h => h.includes('编号')),
      name: headers.findIndex(h => h.includes('姓名')),
      phone: headers.findIndex(h => h.includes('手机') || h.includes('电话')),
      dob: headers.findIndex(h => h.includes('出生') || h.includes('生日')),
      age: headers.findIndex(h => h.includes('年龄')),
      address: headers.findIndex(h => h.includes('地址') || h.includes('居住')),
      notes: headers.findIndex(h => h.includes('备注') && !h.includes('管理')),
      mgmtNotes: headers.findIndex(h => h.includes('管理备注')),
    };

    // 5. Identify Date Columns (Any header containing "x.x" e.g. "4.26" or "5.1")
    const dateIndices: number[] = [];
    const dateHeaders: string[] = [];

    headers.forEach((h, idx) => {
      if (/\d+\.\d+/.test(h)) {
        dateIndices.push(idx);
        dateHeaders.push(h);
      }
    });

    // 6. Sync Date Columns
    const detectedDates = dateHeaders.map(h => h.match(/(\d+\.\d+)/)?.[1] || h);
    const uniqueDetectedDates = Array.from(new Set([...availableDates, ...detectedDates]))
      .sort((a, b) => parseFloat(a) - parseFloat(b));
    setAvailableDates(uniqueDetectedDates);

    // 7. Parse Rows
    const newRecords: RegistrationRecord[] = [];

    for (let i = 1; i < lines.length; i++) {
      // Split row using same separator
      let cols = lines[i].split(separator).map(c => c.trim().replace(/^"|"$/g, ''));

      // If CSV line is complex (quoted strings with commas), simple split might fail. 
      // For now we assume standard Excel export format.
      if (cols.length < 2) continue;

      const getValue = (index: number) => (index !== -1 && cols[index]) ? cols[index] : '';

      // Build Availability Map
      const availabilityMap: Record<string, string> = {};
      dateIndices.forEach((colIdx, headerIdx) => {
        const val = cols[colIdx] || '';
        const rawHeader = dateHeaders[headerIdx];
        const dateKey = rawHeader.match(/(\d+\.\d+)/)?.[1] || rawHeader;

        // Map values to states
        let state = 'EMPTY';
        if (['1', '√', '全', 'FULL'].some(v => val.includes(v))) state = 'FULL';
        else if (['2', '早', '上', 'AM'].some(v => val.includes(v))) state = 'AM';
        else if (['3', '晚', '下', 'PM'].some(v => val.includes(v))) state = 'PM';
        else if (['4', '缺', 'ABSENT'].some(v => val.includes(v))) state = 'ABSENT';

        if (state !== 'EMPTY') availabilityMap[dateKey] = state;
      });

      const record: RegistrationRecord = {
        id: crypto.randomUUID(),
        registrationNumber: getValue(idxMap.num) || String(records.length + newRecords.length + 1),
        name: getValue(idxMap.name) || '未知姓名',
        phone: getValue(idxMap.phone),
        dob: getValue(idxMap.dob),
        age: getValue(idxMap.age),
        address: getValue(idxMap.address),
        notes: getValue(idxMap.notes),
        managementNotes: getValue(idxMap.mgmtNotes),
        submissionTime: new Date().toISOString(),
        availability: JSON.stringify(availabilityMap),
        isTalent: false
      };

      // Validation: Must have at least a name or phone
      if (record.name !== '未知姓名' || record.phone) {
        newRecords.push(record);
      }
    }

    if (newRecords.length > 0) {
      onUpdateRecords([...records, ...newRecords]);
      alert(`成功导入 ${newRecords.length} 条数据！\n已同步日期列：${detectedDates.join(', ')}`);
    } else {
      alert('未能识别有效数据，请检查文件格式。建议包含“姓名”列。');
    }
  };

  const handleClearAll = () => {
    if (confirm('确定要清空所有报名记录吗？此操作不可恢复。')) {
      onUpdateRecords([]);
    }
  };

  const handleDeleteRecord = (id: string) => {
    if (confirm('确定删除该条记录吗？')) {
      onUpdateRecords(records.filter(r => r.id !== id));
    }
  };

  // Availability Toggle Logic
  const toggleAvailability = (recordId: string, dateKey: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;

    let availMap: Record<string, string> = {};
    try {
      availMap = JSON.parse(record.availability || '{}');
    } catch (e) { availMap = {} }

    const currentState = (availMap[dateKey] as AvailabilityState) || 'EMPTY';
    const currentIndex = AVAILABILITY_STATES.indexOf(currentState);
    const nextIndex = (currentIndex + 1) % AVAILABILITY_STATES.length;
    const nextState = AVAILABILITY_STATES[nextIndex];

    availMap[dateKey] = nextState;

    const updatedRecords = records.map(r => 
      r.id === recordId ? { ...r, availability: JSON.stringify(availMap) } : r
    );
    onUpdateRecords(updatedRecords);
  };

  const handleExport = () => {
    const csvHeader = ['编号,姓名,手机号,出生日期,年龄,现居住地址,备注,管理备注', ...availableDates].join(',');

    const csvRows = records.map(record => {
      let availMap: Record<string, string> = {};
      try { availMap = JSON.parse(record.availability || '{}'); } catch(e) {}

      const availValues = availableDates.map(key => {
        const stateKey = (availMap[key] as AvailabilityState) || 'EMPTY';
        return STATE_CONFIG[stateKey]?.shortLabel || '';
      });

      // Escape quotes for CSV
      const escape = (str: string | undefined) => `"${(str || '').replace(/"/g, '""')}"`;

      return [
        escape(record.registrationNumber),
        escape(record.name),
        escape(record.phone),
        escape(record.dob),
        escape(record.age),
        escape(record.address),
        escape(record.notes),
        escape(record.managementNotes),
        ...availValues.map(escape)
      ].join(',');
    });

    const csvContent = "\ufeff" + [csvHeader, ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `STAFF报名名单_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleAddNew = () => {
    const newRecord: RegistrationRecord = {
      id: crypto.randomUUID(),
      registrationNumber: String(records.length + 1),
      name: '',
      phone: '',
      dob: '',
      age: '',
      address: '',
      notes: '',
      managementNotes: '',
      submissionTime: new Date().toISOString(),
      availability: '{}',
      isTalent: false
    };
    setEditingRecord(newRecord);
    setIsEditModalOpen(true);
  };

  const handleSaveModal = () => {
    if (!editingRecord) return;

    // Check if it's a new record or existing one being updated
    const exists = records.some(r => r.id === editingRecord.id);
    let updatedRecords;

    if (exists) {
       updatedRecords = records.map(r => r.id === editingRecord.id ? editingRecord : r);
    } else {
       // Add new record to the top
       updatedRecords = [editingRecord, ...records];
    }

    onUpdateRecords(updatedRecords);
    setIsEditModalOpen(false);
    setEditingRecord(null);
  };

  // Date Management Handlers
  const handleAddDate = () => {
    if (newDateInput && !availableDates.includes(newDateInput)) {
      setAvailableDates([...availableDates, newDateInput]);
      setNewDateInput('');
    }
  };

  const handleRemoveDate = (dateToRemove: string) => {
    if (confirm(`确定要移除 "${dateToRemove}" 这一列吗？`)) {
      setAvailableDates(availableDates.filter(d => d !== dateToRemove));
    }
  };

  return (
    <div className="space-y-4 animate-fade-in pb-24">
      {/* Header */}
      <div>
         <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
           <FileText className="text-indigo-600" /> STAFF报名管理
         </h1>
         <p className="text-gray-500 text-sm mt-1">导入并管理报名人员电子名册</p>
      </div>

      {/* Unified Toolbar */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-4 items-center justify-between">

         {/* Search Area */}
         <div className="flex items-center gap-3 flex-1 w-full md:w-auto">
             <div className="relative flex-1 w-full md:max-w-md">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input 
                  type="text" 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="搜索姓名、编号、手机号或备注..."
