    setFormData(prev => ({
      ...prev,
      fields: prev.fields.map(f => f.id === id ? { ...f, ...updates } : f)
    }));
  };

  const handleSaveClick = () => {
    setIsSaving(true);
    onSave(formData);
    setTimeout(() => setIsSaving(false), 2000);
