import React, { useState, useEffect } from 'react';
import { Share2, Copy, Eye, QrCode, ExternalLink, ArrowLeft, FileText, Check, Download, Rocket, Link as LinkIcon, Printer } from 'lucide-react';
import QRCode from 'qrcode';
import { FormTemplate } from '../types';

interface FormShareDashboardProps {
  form: FormTemplate; // Need full form object for ID/Token
  onBack: () => void;
  onPreview: () => void;
  customDomain: string;
}

const FormShareDashboard: React.FC<FormShareDashboardProps> = ({ form, onBack, onPreview, customDomain }) => {
  const [qrCodeUrl, setQrCodeUrl] = useState('');
  const [copied, setCopied] = useState(false);

  // Dynamic link generation using persistent ID/Token
  // Using shareToken ensures the link never changes even if we change the form title
  const baseUrl = customDomain || "https://workpulse.app";
  const shareLink = `${baseUrl}/f/${form.shareToken || form.id}`;

  useEffect(() => {
    QRCode.toDataURL(shareLink, { width: 600, margin: 2, color: { dark: '#4338ca', light: '#ffffff' } })
      .then(url => setQrCodeUrl(url))
      .catch(err => console.error(err));
  }, [shareLink]);

  const handleCopy = () => {
    navigator.clipboard.writeText(shareLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownloadQR = () => {
    if (!qrCodeUrl) return;
    const link = document.createElement('a');
    link.href = qrCodeUrl;
    link.download = `QR_${form.title}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
