const generateId = () => {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  return Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
};

const formatRegNum = (input: string | number) => {
  const str = String(input).trim();
  if (/^\d+$/.test(str)) {
    return str.padStart(5, '0');
  }
  return str;
};

// Mapping Interface
interface FieldMapping {
  name: string;
  phone: string;
  address: string;
  age: string;
  dob: string;
  schedule: string;
  notes: string;
}

const StaffRegistration: React.FC<StaffRegistrationProps> = ({ 
  records, 
  onUpdateRecords, 
  forms = [],
  formSubmissions = []
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<RegistrationRecord | null>(null);

  // Display Settings
  const [displaySettings, setDisplaySettings] = useState({
    showPhone: true,
    showDOB: true,
    showAddress: true
  });
  const [isDisplaySettingsOpen, setIsDisplaySettingsOpen] = useState(false);

  // Load display settings from local storage
  useEffect(() => {
    const saved = localStorage.getItem('staffRegDisplaySettings');
    if (saved) {
      setDisplaySettings(JSON.parse(saved));
    }
  }, []);

  const toggleDisplaySetting = (key: keyof typeof displaySettings) => {
    const newSettings = { ...displaySettings, [key]: !displaySettings[key] };
    setDisplaySettings(newSettings);
    localStorage.setItem('staffRegDisplaySettings', JSON.stringify(newSettings));
  };

  // Date Management State - Derived purely from records
  const [availableDates, setAvailableDates] = useState<string[]>(["4.26", "5.1", "5.2", "5.3", "5.4", "5.5"]);

  // Sync Modal State
  const [isSyncModalOpen, setIsSyncModalOpen] = useState(false);
  const [selectedFormId, setSelectedFormId] = useState<string>('');
  const [mapping, setMapping] = useState<FieldMapping>({
    name: '', phone: '', address: '', age: '', dob: '', schedule: '', notes: ''
  });

  // Auto-map when form selected
  useEffect(() => {
    if (selectedFormId) {
      const form = forms.find(f => f.id === selectedFormId);
      if (form) {
        const newMapping: FieldMapping = {
          name: form.fields.find(f => f.label.includes('姓名') || f.label.includes('名字'))?.id || '',
          phone: form.fields.find(f => f.type === 'PHONE' || f.label.includes('手机') || f.label.includes('电话'))?.id || '',
          address: form.fields.find(f => f.type === 'ADDRESS' || f.label.includes('地址') || f.label.includes('住址'))?.id || '',
          age: form.fields.find(f => f.type === 'NUMBER' && (f.label.includes('年龄') || f.label.includes('岁')))?.id || '',
          dob: form.fields.find(f => f.type === 'DATE' && (f.label.includes('出生') || f.label.includes('生日')))?.id || '',
          schedule: form.fields.find(f => f.type === 'SCHEDULE')?.id || '',
          notes: form.fields.find(f => f.type === 'NOTES' || f.label.includes('备注'))?.id || ''
        };
        setMapping(newMapping);
      }
    }
  }, [selectedFormId, forms]); // Re-run if forms update (e.g. labels change)

  // Derived filtered records
  const filteredRecords = useMemo(() => {
    return records.filter(record => 
      record.name.includes(searchTerm) || 
      record.registrationNumber.includes(searchTerm) ||
      (record.notes && record.notes.includes(searchTerm)) ||
      (record.phone && record.phone.includes(searchTerm))
    );
  }, [records, searchTerm]);

  // Handle Sync from Form with Mapping
  const handleSyncFromForm = () => {
    if (!selectedFormId) return;
    const form = forms.find(f => f.id === selectedFormId);
    if (!form) return;

    // Get submissions for this form
    const submissions = formSubmissions.filter(s => s.formId === selectedFormId);
    if (submissions.length === 0) {
      alert("该表单暂无提交数据");
      return;
    }

    let newCount = 0;
    const newRecords: RegistrationRecord[] = [];

    // Find current max ID for auto-increment
    let currentMaxId = records.reduce((max, r) => {
        const n = parseInt(r.registrationNumber, 10);
        return !isNaN(n) && n > max ? n : max;
    }, 0);

    submissions.forEach(sub => {
       // Values from mapping
       const name = mapping.name ? sub.data[mapping.name] : '未知姓名';
       const phone = mapping.phone ? sub.data[mapping.phone] : '';

       // Check duplicates (by phone if exists, else by name)
       const isDuplicate = records.some(r => (phone && r.phone === phone) || (!phone && r.name === name));
       if (isDuplicate) return;

       const address = mapping.address ? sub.data[mapping.address] : '';
       const dob = mapping.dob ? sub.data[mapping.dob] : '';
       let age = mapping.age ? sub.data[mapping.age] : '';

       // Calculate age if DOB exists but age doesn't
       if (!age && dob) {
          try {
            const birthYear = new Date(dob).getFullYear();
            const currentYear = new Date().getFullYear();
            const calcAge = currentYear - birthYear;
            if (!isNaN(calcAge)) age = String(calcAge) + '岁';
          } catch(e) {}
       } else if (age && !String(age).includes('岁')) {
          age = age + '岁';
       }

       // Explicit Notes Field
       const explicitNotes = mapping.notes ? sub.data[mapping.notes] : '';

       // Schedule Field
       let availabilityMap: Record<string, string> = {};
       if (mapping.schedule) {
          const subSched = sub.data[mapping.schedule]; 
          if (subSched && typeof subSched === 'object') {
             availabilityMap = subSched;
          }
       }

       // Other fields -> Append to Notes
       const mappedIds = Object.values(mapping).filter(Boolean);
       const extraNotes: string[] = [];

       if (explicitNotes) extraNotes.push(explicitNotes);

       form.fields.forEach(f => {
          if (mappedIds.includes(f.id)) return; // Skip mapped fields
          const val = sub.data[f.id];
          if (val === undefined || val === null || val === '') return;

          // Cards logic (ID Card, Bank Card) -> Notes
          if (f.type === 'ID_CARD') {
             extraNotes.push(`证件号: ${val}`);
          } else if (f.type === 'BANK_CARD') {
             extraNotes.push(`银行卡: ${val}`);
          } else {
             // Generic fallback
             extraNotes.push(`${f.label}: ${val}`);
          }
       });

       currentMaxId++;

       newRecords.push({
          id: generateId(),
          registrationNumber: formatRegNum(currentMaxId),
          name: String(name),
          phone: String(phone),
          dob: String(dob),
          age: String(age),
          address: String(address),
          notes: extraNotes.join('; '),
          managementNotes: '表单同步导入',
          submissionTime: sub.submittedAt,
          availability: JSON.stringify(availabilityMap),
          isTalent: false
       });
       newCount++;
    });

    if (newCount > 0) {
       // Merge date headers automatically
       const newDateHeaders = new Set([...availableDates]);
       newRecords.forEach(r => {
          const map = JSON.parse(r.availability || '{}');
          Object.keys(map).forEach(d => newDateHeaders.add(d));
       });

       setAvailableDates(Array.from(newDateHeaders).sort((a,b) => parseFloat(a)-parseFloat(b)));
       onUpdateRecords([...records, ...newRecords]);
       alert(`成功同步 ${newCount} 条新数据！`);
       setIsSyncModalOpen(false);
    } else {
       alert("没有新的数据需要同步 (可能已存在或表单为空)");
    }
  };

  const handleClearAll = (e?: React.MouseEvent) => {
    if (e) { e.stopPropagation(); e.preventDefault(); }
    if (records.length === 0) return;
    if (window.confirm(`确定要清空所有 ${records.length} 条报名记录吗？\n警告：此操作不可恢复！`)) {
      onUpdateRecords([]);
    }
  };

  const handleDeleteRecord = (id: string, name: string) => {
    if (window.confirm(`确定要删除 "${name}" 吗？此操作不可恢复。`)) {
      const newRecords = records.filter(r => r.id !== id);
      onUpdateRecords(newRecords);
    }
  };

  const toggleAvailability = (recordId: string, dateKey: string) => {
    const record = records.find(r => r.id === recordId);
    if (!record) return;
    let availMap: Record<string, string> = {};
    try { availMap = JSON.parse(record.availability || '{}'); } catch (e) { availMap = {} }
    const currentState = (availMap[dateKey] as AvailabilityState) || 'EMPTY';
    const currentIndex = AVAILABILITY_STATES.indexOf(currentState);
    const nextIndex = (currentIndex + 1) % AVAILABILITY_STATES.length;
    const nextState = AVAILABILITY_STATES[nextIndex];
    availMap[dateKey] = nextState;
    const updatedRecords = records.map(r => r.id === recordId ? { ...r, availability: JSON.stringify(availMap) } : r);
    onUpdateRecords(updatedRecords);
  };

  const handleExport = () => {
    const csvHeader = ['编号,姓名,手机号,出生日期,年龄,现居住地址,备注,管理备注', ...availableDates].join(',');
    const csvRows = records.map(record => {
      let availMap: Record<string, string> = {};
      try { availMap = JSON.parse(record.availability || '{}'); } catch(e) {}
      const availValues = availableDates.map(key => {
        const stateKey = (availMap[key] as AvailabilityState) || 'EMPTY';
        return STATE_CONFIG[stateKey]?.shortLabel || '';
      });
      const escape = (str: string | undefined) => `"${(str || '').replace(/"/g, '""')}"`;
      return [
        escape(record.registrationNumber),
        escape(record.name),
        escape(record.phone),
        escape(record.dob),
        escape(record.age),
        escape(record.address),
        escape(record.notes),
        escape(record.managementNotes),
        ...availValues.map(escape)
      ].join(',');
    });
    const csvContent = "\ufeff" + [csvHeader, ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `STAFF报名名单_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleAddNew = () => {
    const maxId = records.reduce((max, r) => {
        const n = parseInt(r.registrationNumber, 10);
        return !isNaN(n) && n > max ? n : max;
    }, 0);
    const nextId = formatRegNum(maxId + 1);
    const newRecord: RegistrationRecord = {
      id: generateId(),
      registrationNumber: nextId,
      name: '',
      phone: '',
      dob: '',
      age: '',
      address: '',
      notes: '',
      managementNotes: '',
      submissionTime: new Date().toISOString(),
      availability: '{}',
      isTalent: false
    };
    setEditingRecord(newRecord);
    setIsEditModalOpen(true);
  };

  const handleSaveModal = () => {
    if (!editingRecord) return;
    const exists = records.some(r => r.id === editingRecord.id);
    let updatedRecords;
    if (exists) {
       updatedRecords = records.map(r => r.id === editingRecord.id ? editingRecord : r);
    } else {
       updatedRecords = [editingRecord, ...records];
    }
    onUpdateRecords(updatedRecords);
    setIsEditModalOpen(false);
    setEditingRecord(null);
  };

  return (
    <div className="space-y-4 animate-fade-in pb-24">
      {/* Header */}
      <div>
         <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
           <FileText className="text-indigo-600" /> STAFF报名管理
         </h1>
         <p className="text-gray-500 text-sm mt-1">管理报名人员电子名册与排班状态</p>
      </div>

      {/* Unified Toolbar */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col md:flex-row gap-4 items-center justify-between">

         {/* Search Area */}
         <div className="flex items-center gap-3 flex-1 w-full md:w-auto">
             <div className="relative flex-1 w-full md:max-w-md">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input 
                  type="text" 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="搜索姓名、编号、手机号或备注..."
                  className="w-full pl-9 pr-4 py-2.5 border border-gray-200 rounded-lg text-sm outline-none focus:border-indigo-400 focus:ring-2 focus:ring-indigo-50 transition-all bg-gray-50 focus:bg-white"
                />
             </div>
             <div className="hidden md:flex items-center px-3 py-2 bg-gray-50 rounded-lg border border-gray-200 text-xs text-gray-500 whitespace-nowrap">
                共 <span className="font-bold text-gray-800 mx-1">{filteredRecords.length}</span> 人
             </div>
         </div>

         {/* Actions Group */}
         <div className="flex flex-wrap items-center gap-2 w-full md:w-auto justify-end">
           <button 
             onClick={() => setIsSyncModalOpen(true)}
             className="px-3 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-sm shadow-indigo-200"
             title="从表单导入数据"
           >
             <RefreshCw size={16} /> 表单同步
           </button>

           <div className="w-px h-8 bg-gray-200 hidden md:block mx-1"></div>

           <button 
             onClick={handleAddNew} 
             className="px-3 py-2 bg-white text-gray-600 rounded-lg text-sm font-medium hover:bg-gray-50 hover:text-gray-800 transition-colors flex items-center gap-1.5 shadow-sm border border-gray-200"
           >
             <Plus size={16} /> 添加
           </button>

           <button 
             onClick={handleExport} 
             className="px-3 py-2 bg-white text-gray-600 rounded-lg text-sm font-medium hover:bg-gray-50 hover:text-gray-800 transition-colors flex items-center gap-1.5 shadow-sm border border-gray-200"
           >
             <Download size={16} /> 导出
           </button>

           <button 
             onClick={(e) => handleClearAll(e)} 
             className="p-2 text-red-500 bg-white border border-red-100 hover:bg-red-50 rounded-lg transition-colors"
             title="清空所有数据"
           >
             <Trash2 size={16} />
           </button>
         </div>
      </div>

      {/* Main Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto min-h-[400px]">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 text-gray-500 text-xs uppercase border-b border-gray-200">
                <th className="p-4 w-[60px] text-center font-bold">编号</th>
                <th className="p-4 w-[280px] text-center font-bold relative group">
                   <div className="flex items-center justify-center gap-2">
                      基本信息
                      <button 
                        onClick={() => setIsDisplaySettingsOpen(!isDisplaySettingsOpen)}
                        className="text-gray-400 hover:text-indigo-600 transition-colors p-1 rounded-md hover:bg-gray-100"
                        title="设置显示字段"
                      >
                         <Settings size={14} />
                      </button>
                   </div>

                   {/* Display Settings Popover */}
                   {isDisplaySettingsOpen && (
                      <div className="absolute top-full left-1/2 -translate-x-1/2 mt-2 w-48 bg-white rounded-xl shadow-xl border border-gray-100 z-50 p-2 animate-in fade-in zoom-in duration-200">
                         <div className="text-xs font-bold text-gray-400 px-3 py-2">显示字段开关</div>
                         <div className="space-y-1">
                            <button 
                              onClick={() => toggleDisplaySetting('showPhone')}
                              className="w-full flex items-center justify-between px-3 py-2 hover:bg-gray-50 rounded-lg text-sm text-gray-700"
                            >
                               手机号 {displaySettings.showPhone ? <Eye size={14} className="text-indigo-600" /> : <EyeOff size={14} className="text-gray-400" />}
                            </button>
                            <button 
                              onClick={() => toggleDisplaySetting('showDOB')}
                              className="w-full flex items-center justify-between px-3 py-2 hover:bg-gray-50 rounded-lg text-sm text-gray-700"
                            >
                               生日/年龄 {displaySettings.showDOB ? <Eye size={14} className="text-indigo-600" /> : <EyeOff size={14} className="text-gray-400" />}
                            </button>
                            <button 
                              onClick={() => toggleDisplaySetting('showAddress')}
                              className="w-full flex items-center justify-between px-3 py-2 hover:bg-gray-50 rounded-lg text-sm text-gray-700"
                            >
                               地址 {displaySettings.showAddress ? <Eye size={14} className="text-indigo-600" /> : <EyeOff size={14} className="text-gray-400" />}
                            </button>
                         </div>
                         {/* Close Overlay */}
                         <div className="fixed inset-0 z-[-1]" onClick={() => setIsDisplaySettingsOpen(false)}></div>
                      </div>
                   )}
                </th>
                <th className="p-4 w-[150px] text-center font-bold">备注</th>
                <th className="p-4 w-[150px] text-center font-bold">管理备注</th>
                <th className="p-4 text-center font-bold bg-indigo-50/30">
                  <div className="flex flex-col items-center gap-1">
                    <span>可参加时间</span>
                    <span className="text-[10px] font-normal text-gray-400 normal-case">(点击切换)</span>
                  </div>
                </th>
                <th className="p-4 w-[100px] text-right font-bold">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredRecords.length === 0 ? (
                <tr>
                   <td colSpan={6} className="py-20 text-center text-gray-400">
                      <div className="flex flex-col items-center justify-center">
                         <FileSpreadsheet size={48} className="mb-4 opacity-20" />
                         <p className="text-lg font-medium">暂无数据</p>
                         <p className="text-sm mt-1">请从表单同步或手动添加数据</p>
                      </div>
                   </td>
                </tr>
              ) : (
                filteredRecords.map((record) => {
                  let availMap: Record<string, string> = {};
                  try { availMap = JSON.parse(record.availability || '{}'); } catch (e) {}

                  return (
                    <tr key={record.id} className="hover:bg-gray-50 transition-colors group">
                      <td className="p-4 text-center align-middle">
                        <span className="inline-block bg-gray-100 text-gray-600 px-2 py-1 rounded text-xs font-mono font-bold">
                          {record.registrationNumber}
                        </span>
                      </td>
                      <td className="p-4 align-middle">
                        <div className="flex flex-col items-center gap-1">
                           <div className="flex items-center justify-center gap-2">
                             <span className="font-bold text-gray-800 text-sm">{record.name}</span>
                             {displaySettings.showPhone && record.phone && <span className="text-xs text-gray-500 font-mono tracking-tight">{record.phone}</span>}
                           </div>

                           {displaySettings.showDOB && (record.dob || record.age) && (
                             <div className="flex items-center justify-center gap-2 text-xs">
                                {record.dob && <span className="text-gray-500">{record.dob}</span>}
                                {record.age && <span className="text-gray-500 bg-gray-100 px-1 rounded">{record.age}</span>}
                             </div>
                           )}

                           {displaySettings.showAddress && record.address && (
                             <div className="text-xs text-gray-400 text-center line-clamp-1 max-w-[220px]" title={record.address}>{record.address}</div>
                           )}
                        </div>
                      </td>
                      <td className="p-4 align-middle text-center">
                         <div className="text-xs text-gray-600 line-clamp-3 leading-relaxed" title={record.notes}>
                            {record.notes || <span className="text-gray-300 italic">-</span>}
                         </div>
                      </td>
                      <td className="p-4 align-middle text-center">
                         <div className="text-xs text-indigo-700 bg-indigo-50/50 p-2 rounded border border-indigo-100/50 line-clamp-3 leading-relaxed min-h-[3em] flex items-center justify-center cursor-pointer hover:bg-indigo-50 hover:border-indigo-200 transition-colors" onClick={() => { setEditingRecord(record); setIsEditModalOpen(true); }}>
                            {record.managementNotes || <span className="text-indigo-300 flex items-center gap-1"><Edit size={10} /> 点击添加</span>}
                         </div>
                      </td>
                      <td className="p-2 align-middle bg-indigo-50/10">
                         <div className={`grid gap-1 w-full max-w-[220px] mx-auto`} style={{ gridTemplateColumns: 'repeat(4, minmax(0, 1fr))' }}>
                            {availableDates.map(date => {
                               const stateKey = (availMap[date] as AvailabilityState) || 'EMPTY';
                               const config = STATE_CONFIG[stateKey] || STATE_CONFIG.EMPTY;
                               return (
                                 <button
                                   key={date}
                                   onClick={() => toggleAvailability(record.id, date)}
                                   className={`flex flex-col items-center justify-center w-full aspect-square rounded border transition-all duration-200 hover:shadow-sm hover:scale-105 active:scale-95 ${config.bg} ${config.border}`}
                                   title={`日期: ${date}, 状态: ${config.label}`}
                                 >
                                    <span className={`text-[9px] font-bold leading-none mb-0.5 ${stateKey === 'EMPTY' ? 'text-gray-400' : 'text-gray-600'}`}>{date}</span>
                                    <div className={`flex items-center justify-center gap-0.5 ${config.text} transform scale-90`}>
                                       {config.icon}
                                       <span className="text-[10px] font-bold">{config.shortLabel}</span>
                                    </div>
                                 </button>
                               );
                            })}
                         </div>
                      </td>
                      <td className="p-4 text-right align-middle">
                         <div className="flex justify-end items-center gap-2">
                            <button onClick={() => { setEditingRecord(record); setIsEditModalOpen(true); }} className="w-8 h-8 flex items-center justify-center rounded-lg text-indigo-500 bg-indigo-50 hover:bg-indigo-100 border border-indigo-100 transition-colors">
                              <Edit size={14} />
                            </button>
                            <button onClick={(e) => { e.stopPropagation(); e.nativeEvent.stopImmediatePropagation(); handleDeleteRecord(record.id, record.name); }} className="w-8 h-8 flex items-center justify-center rounded-lg text-gray-400 hover:text-red-500 hover:bg-red-50 border border-transparent hover:border-red-100 transition-colors">
                              <Trash2 size={14} />
                            </button>
                         </div>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Sync Modal with MAPPING */}
      {isSyncModalOpen && (
         <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-xl w-full max-w-xl overflow-hidden animate-in zoom-in duration-200 flex flex-col max-h-[90vh]">
               <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                  <h3 className="font-bold text-gray-800 flex items-center gap-2">
                     <RefreshCw size={18} /> 同步表单数据
                  </h3>
                  <button onClick={() => setIsSyncModalOpen(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
               </div>

               <div className="p-6 space-y-6 overflow-y-auto">

                  {/* Step 1: Select Form */}
                  <div className="space-y-2">
                     <label className="text-xs font-bold text-gray-500 uppercase">1. 选择来源表单</label>
                     <div className="relative">
                        <select 
                           value={selectedFormId}
                           onChange={(e) => setSelectedFormId(e.target.value)}
                           className="w-full border border-gray-300 rounded-lg p-3 text-sm appearance-none outline-none focus:ring-2 focus:ring-indigo-500 bg-white"
                        >
                           <option value="" disabled>请选择一个表单...</option>
                           {forms.map(f => (
                              <option key={f.id} value={f.id}>{f.title} ({formSubmissions.filter(s => s.formId === f.id).length} 条数据)</option>
                           ))}
                        </select>
                        <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">▼</div>
                     </div>
                  </div>

                  {/* Step 2: Field Mapping */}
                  {selectedFormId && (
                     <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                        <div className="flex items-center justify-between">
