                         onChange={(e) => setEditingRecord({...editingRecord, name: e.target.value})}
                         className="w-full border border-gray-300 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                         placeholder="必填"
                       />
                    </div>
                    <div className="space-y-1">
                       <label className="text-xs font-bold text-gray-500">编号</label>
                       <input 
                         type="text" 
                         value={editingRecord.registrationNumber}
                         onChange={(e) => setEditingRecord({...editingRecord, registrationNumber: e.target.value})}
                         className="w-full border border-gray-300 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                       />
                    </div>
                 </div>

                 {/* Phone Number Field */}
                 <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500">手机号</label>
                    <input 
                      type="text" 
                      value={editingRecord.phone || ''}
                      onChange={(e) => setEditingRecord({...editingRecord, phone: e.target.value})}
                      className="w-full border border-gray-300 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                      placeholder="选填"
                    />
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                       <label className="text-xs font-bold text-gray-500">出生日期</label>
                       <input 
                         type="text" 
                         value={editingRecord.dob || ''}
                         onChange={(e) => setEditingRecord({...editingRecord, dob: e.target.value})}
                         className="w-full border border-gray-300 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                         placeholder="YYYY-MM-DD"
                       />
                    </div>
                    <div className="space-y-1">
                       <label className="text-xs font-bold text-gray-500">年龄</label>
                       <input 
                         type="text" 
                         value={editingRecord.age || ''}
                         onChange={(e) => setEditingRecord({...editingRecord, age: e.target.value})}
                         className="w-full border border-gray-300 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                       />
                    </div>
                 </div>

                 <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500">现居住地址</label>
                    <input 
                      type="text" 
                      value={editingRecord.address || ''}
                      onChange={(e) => setEditingRecord({...editingRecord, address: e.target.value})}
                      className="w-full border border-gray-300 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                 </div>

                 <div className="space-y-1">
                    <label className="text-xs font-bold text-gray-500">备注 (用户填写)</label>
                    <textarea 
                      rows={3}
                      value={editingRecord.notes || ''}
                      onChange={(e) => setEditingRecord({...editingRecord, notes: e.target.value})}
                      className="w-full border border-gray-300 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                    />
                 </div>

                 <div className="space-y-1">
                    <label className="text-xs font-bold text-indigo-600 flex items-center gap-1">
                       <Settings size={12} /> 管理备注 (后台专用)
                    </label>
                    <textarea 
                      rows={3}
                      value={editingRecord.managementNotes || ''}
                      onChange={(e) => setEditingRecord({...editingRecord, managementNotes: e.target.value})}
                      className="w-full border border-indigo-200 bg-indigo-50/30 rounded p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none text-indigo-900"
                      placeholder="在此输入仅管理员可见的备注..."
                    />
                 </div>
              </div>

              <div className="p-6 border-t border-gray-100 flex gap-3 bg-gray-50">
                 <button 
                   onClick={() => setIsEditModalOpen(false)}
                   className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-white transition-colors"
                 >
                   取消
                 </button>
                 <button 
                   onClick={handleSaveModal}
                   className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm"
                 >
                   保存
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffRegistration;
